rn err;\n}\n\nstatic int damon_reclaim_handle_commit_inputs(void)\n{\n\tint err;\n\n\tif (!commit_inputs)\n\t\treturn 0;\n\n\terr = damon_reclaim_apply_parameters();\n\tcommit_inputs = false;\n\treturn err;\n}\n\nstatic int damon_reclaim_damon_call_fn(void *arg)\n{\n\tstruct damon_ctx *c = arg;\n\tstruct damos *s;\n\n\t/* update the stats parameter */\n\tdamon_for_each_scheme(s, c)\n\t\tdamon_reclaim_stat = s->stat;\n\n\treturn damon_reclaim_handle_commit_inputs();\n}\n\nstatic struct damon_call_control call_control = {\n\t.fn = damon_reclaim_damon_call_fn,\n\t.repeat = true,\n};\n\nstatic int damon_reclaim_turn(bool on)\n{\n\tint err;\n\n\tif (!on) {\n\t\terr = damon_stop(&ctx, 1);\n\t\tif (!err)\n\t\t\tkdamond_pid = -1;\n\t\treturn err;\n\t}\n\n\terr = damon_reclaim_apply_parameters();\n\tif (err)\n\t\treturn err;\n\n\terr = damon_start(&ctx, 1, true);\n\tif (err)\n\t\treturn err;\n\tkdamond_pid = damon_kdamond_pid(ctx);\n\tif (kdamond_pid < 0)\n\t\treturn kdamond_pid;\n\treturn damon_call(ctx, &call_control);\n}\n\nstatic int damon_reclaim_addr_unit_store(const char *val,\n\t\tconst struct kernel_param *kp)\n{\n\tunsigned long input_addr_unit;\n\tint err = kstrtoul(val, 0, &input_addr_unit);\n\n\tif (err)\n\t\treturn err;\n\tif (!input_addr_unit)\n\t\treturn -EINVAL;\n\n\taddr_unit = input_addr_unit;\n\treturn 0;\n}\n\nstatic const struct kernel_param_ops addr_unit_param_ops = {\n\t.set = damon_reclaim_addr_unit_store,\n\t.get = param_get_ulong,\n};\n\nmodule_param_cb(addr_unit, &addr_unit_param_ops, &addr_unit, 0600);\nMODULE_PARM_DESC(addr_unit,\n\t\"Scale factor for DAMON_RECLAIM to ops address conversion (default: 1)\");\n\nstatic int damon_reclaim_enabled_store(const char *val,\n\t\tconst struct kernel_param *kp)\n{\n\tbool is_enabled = enabled;\n\tbool enable;\n\tint err;\n\n\terr = kstrtobool(val, &enable);\n\tif (err)\n\t\treturn err;\n\n\tif (is_enabled == enable)\n\t\treturn 0;\n\n\t/* Called before init function.  The function will handle this. */\n\tif (!damon_initialized())\n\t\tgoto set_param_out;\n\n\terr = damon_reclaim_turn(enable);\n\tif (err)\n\t\treturn err;\n\nset_param_out:\n\tenabled = enable;\n\treturn err;\n}\n\nstatic const struct kernel_param_ops enabled_param_ops = {\n\t.set = damon_reclaim_enabled_store,\n\t.get = param_get_bool,\n};\n\nmodule_param_cb(enabled, &enabled_param_ops, &enabled, 0600);\nMODULE_PARM_DESC(enabled,\n\t\"Enable or disable DAMON_RECLAIM (default: disabled)\");\n\nstatic int __init damon_reclaim_init(void)\n{\n\tint err;\n\n\tif (!damon_initialized()) {\n\t\terr = -ENOMEM;\n\t\tgoto out;\n\t}\n\terr = damon_modules_new_paddr_ctx_target(&ctx, &target);\n\tif (err)\n\t\tgoto out;\n\n\tcall_control.data = ctx;\n\n\t/* 'enabled' has set before this function, probably via command line */\n\tif (enabled)\n\t\terr = damon_reclaim_turn(true);\n\nout:\n\tif (err && enabled)\n\t\tenabled = false;\n\treturn err;\n}\n\nmodule_init(damon_reclaim_init);","end_line":395,"lines_read":395,"path":"mm/damon/reclaim.c","start_line":1,"total_lines":395}]}",
